// src/components/ChartArea.jsx
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
} from "recharts";

const ChartArea = ({ selectedCompany, isLoading, chartData }) => {
  if (isLoading) {
    return (
      <div className="w-full h-[300px] flex items-center justify-center">
        <p>Loading chart...</p>
      </div>
    );
  }

  if (!selectedCompany || !chartData?.length) {
    return (
      <div className="w-full h-[300px] flex items-center justify-center text-gray-500">
        <p>No chart data available</p>
      </div>
    );
  }

  return (
    <div className="w-full h-[300px] sm:h-[320px] md:h-[320px] lg:h-[380px] xl:h-[400px]">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart
          data={chartData}
          margin={{ top: 10, right: 20, left: 0, bottom: 0 }}
        >
          <XAxis
            dataKey="date"
            tick={{ fontSize: 10 }}
            tickLine={false}
            axisLine={{ stroke: "#e5e7eb" }}
          />
          <YAxis
            tick={{ fontSize: 10 }}
            tickLine={false}
            axisLine={{ stroke: "#e5e7eb" }}
          />
          <Tooltip
            contentStyle={{ fontSize: "12px", borderRadius: "8px" }}
          />
          <Line
            type="monotone"
            dataKey="value"
            stroke="#2563eb"
            strokeWidth={2}
            dot={false}
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default ChartArea;
